package com.recettealarm.app;import android.app.*;import android.os.*;import android.graphics.Color;import android.media.*;import android.net.Uri;import android.view.*;import android.widget.*;import java.util.*;
public class AlarmActivity extends Activity{Ringtone ring;Vibrator vib;int brown=Color.rgb(169,87,47);public void onCreate(Bundle b){super.onCreate(b);getWindow().addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON|WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED|WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON);LinearLayout l=new LinearLayout(this);l.setOrientation(LinearLayout.VERTICAL);l.setPadding(35,80,35,35);l.setBackgroundColor(Color.rgb(255,253,249));setContentView(l);TextView t=new TextView(this);t.setText("TEMPS ÉCOULÉ !\n"+getIntent().getStringExtra("title"));t.setTextSize(32);t.setTypeface(null,1);t.setGravity(1);l.addView(t);TextView n=new TextView(this);n.setText("NOTE IMPORTANTE\n\n"+getIntent().getStringExtra("note")+"\n\nVérifie immédiatement pour éviter que le plat brûle.");n.setTextSize(23);n.setGravity(1);n.setPadding(15,50,15,50);l.addView(n);Button stop=new Button(this);stop.setText("ARRÊTER");stop.setTextColor(Color.WHITE);stop.setBackgroundColor(brown);l.addView(stop,new LinearLayout.LayoutParams(-1,120));Button plus=new Button(this);plus.setText("+5 MIN");l.addView(plus,new LinearLayout.LayoutParams(-1,100));stop.setOnClickListener(v->{stopAlarm();finish();});plus.setOnClickListener(v->{stopAlarm();finish();});startAlarm();}void startAlarm(){try{ring=RingtoneManager.getRingtone(this,RingtoneManager.getDefaultUri(RingtoneManager.TYPE_ALARM));if(ring==null)ring=RingtoneManager.getRingtone(this,RingtoneManager.getDefaultUri(RingtoneManager.TYPE_RINGTONE));ring.play();vib=(Vibrator)getSystemService(VIBRATOR_SERVICE); if(Build.VERSION.SDK_INT>=26)vib.vibrate(VibrationEffect.createWaveform(new long[]{0,700,300,700},0)); else vib.vibrate(new long[]{0,700,300,700},0);}catch(Exception e){}}void stopAlarm(){try{if(ring!=null)ring.stop();if(vib!=null)vib.cancel();}catch(Exception e){}}protected void onDestroy(){super.onDestroy();stopAlarm();}}
